import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getMyReservations, cancelReservation } from '../api/reservations';
import toast from 'react-hot-toast';

export default function MyReservationsPage() {
  const [reservations, setReservations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [cancelling, setCancelling] = useState(null);
  const [selectedFilter, setSelectedFilter] = useState('all');
  const [expandedId, setExpandedId] = useState(null);

  const load = () => getMyReservations()
    .then(r => setReservations(r.data.results || r.data))
    .finally(() => setLoading(false));

  useEffect(() => { load(); }, []);

  const handleCancel = async (id) => {
    if (!window.confirm('Are you sure you want to cancel this reservation?')) return;
    setCancelling(id);
    try {
      await cancelReservation(id);
      toast.success('Reservation cancelled successfully.');
      load();
    } catch (e) {
      toast.error(e.response?.data?.detail || 'Could not cancel reservation.');
    } finally {
      setCancelling(null);
    }
  };

  // Filter reservations
  const filteredReservations = reservations.filter(r => {
    if (selectedFilter === 'all') return true;
    return r.status === selectedFilter;
  });

  // Get status badge style
  const getStatusStyle = (status) => {
    switch(status) {
      case 'confirmed':
        return { bg: '#10b981', color: 'white', icon: '✓' };
      case 'pending':
        return { bg: '#f59e0b', color: 'white', icon: '⏳' };
      case 'checked_in':
        return { bg: '#3b82f6', color: 'white', icon: '🏨' };
      case 'checked_out':
        return { bg: '#6b7280', color: 'white', icon: '✓✓' };
      case 'cancelled':
        return { bg: '#ef4444', color: 'white', icon: '✗' };
      default:
        return { bg: '#9ca3af', color: 'white', icon: '•' };
    }
  };

  // Get status label
  const getStatusLabel = (status) => {
    return status.replace('_', ' ').toUpperCase();
  };

  return (
    <div style={{ paddingTop: 72, background: 'linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)', minHeight: '100vh' }}>
      {/* Hero Header */}
      <div style={{ 
        background: 'linear-gradient(135deg, #0a1e3d 0%, #0f2b4c 50%, #1a3a5c 100%)',
        padding: '60px 0 80px',
        position: 'relative',
        overflow: 'hidden'
      }}>
        {/* Animated background elements */}
        <div style={{
          position: 'absolute',
          top: -100,
          right: -100,
          width: 400,
          height: 400,
          borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(201,168,76,0.1) 0%, transparent 70%)',
          animation: 'float 8s ease-in-out infinite'
        }} />
        <div style={{
          position: 'absolute',
          bottom: -50,
          left: -50,
          width: 300,
          height: 300,
          borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(30,95,168,0.15) 0%, transparent 70%)',
          animation: 'float 10s ease-in-out infinite reverse'
        }} />

        <div className="container" style={{ position: 'relative', zIndex: 2, maxWidth: 1200, margin: '0 auto', padding: '0 24px' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', flexWrap: 'wrap', gap: 20 }}>
            <div>
              <div style={{
                display: 'inline-block',
                padding: '6px 16px',
                background: 'rgba(255,255,255,0.1)',
                backdropFilter: 'blur(10px)',
                borderRadius: '100px',
                marginBottom: 20,
                fontSize: '0.7rem',
                fontWeight: 600,
                letterSpacing: '0.1em',
                color: '#c9a84c'
              }}>
                MY ACCOUNT
              </div>
              <h1 style={{ 
                fontFamily: 'var(--font-display, "Playfair Display", serif)', 
                fontSize: 'clamp(2rem, 5vw, 3rem)', 
                fontWeight: 300, 
                color: 'white',
                marginBottom: 12
              }}>
                My Reservations
              </h1>
              <p style={{ color: 'rgba(255,255,255,0.7)', fontSize: '1rem' }}>
                {reservations.length} {reservations.length === 1 ? 'reservation' : 'reservations'} found
              </p>
            </div>
            <Link 
              to="/rooms" 
              style={{
                padding: '12px 28px',
                background: 'linear-gradient(135deg, #c9a84c, #b8923e)',
                borderRadius: '50px',
                color: 'white',
                textDecoration: 'none',
                fontWeight: 600,
                transition: 'all 0.3s',
                display: 'inline-flex',
                alignItems: 'center',
                gap: 8
              }}
              onMouseEnter={e => {
                e.currentTarget.style.transform = 'translateY(-2px)';
                e.currentTarget.style.boxShadow = '0 10px 25px rgba(201,168,76,0.3)';
              }}
              onMouseLeave={e => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.boxShadow = 'none';
              }}
            >
              + New Reservation
            </Link>
          </div>
        </div>
      </div>

      <div className="container" style={{ maxWidth: 1200, margin: '0 auto', padding: '0 24px', marginTop: -40, paddingBottom: 80 }}>
        {/* Filter Tabs */}
        {!loading && reservations.length > 0 && (
          <div style={{
            background: 'white',
            borderRadius: 16,
            padding: 8,
            marginBottom: 32,
            display: 'flex',
            gap: 8,
            flexWrap: 'wrap',
            boxShadow: '0 4px 6px rgba(0,0,0,0.05)'
          }}>
            {['all', 'confirmed', 'pending', 'checked_in', 'checked_out', 'cancelled'].map(filter => (
              <button
                key={filter}
                onClick={() => setSelectedFilter(filter)}
                style={{
                  padding: '10px 24px',
                  background: selectedFilter === filter ? 'linear-gradient(135deg, #c9a84c, #b8923e)' : 'transparent',
                  border: 'none',
                  borderRadius: 12,
                  color: selectedFilter === filter ? 'white' : '#666',
                  fontWeight: 600,
                  cursor: 'pointer',
                  transition: 'all 0.3s',
                  fontSize: '0.85rem',
                  textTransform: 'capitalize'
                }}
              >
                {filter === 'all' ? 'All Reservations' : 
                 filter === 'checked_in' ? 'Checked In' :
                 filter === 'checked_out' ? 'Checked Out' : filter}
              </button>
            ))}
          </div>
        )}

        {loading ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
            {[1,2,3].map(i => (
              <div key={i} style={{
                height: 180,
                borderRadius: 20,
                background: 'linear-gradient(135deg, #f0f0f0 0%, #e0e0e0 100%)',
                animation: 'shimmer 2s infinite'
              }} />
            ))}
          </div>
        ) : filteredReservations.length === 0 ? (
          <div style={{
            textAlign: 'center',
            padding: '80px 40px',
            background: 'white',
            borderRadius: 24,
            boxShadow: '0 10px 30px rgba(0,0,0,0.05)'
          }}>
            <div style={{
              fontSize: '4rem',
              marginBottom: 20,
              animation: 'float 3s ease-in-out infinite'
            }}>
              🏨
            </div>
            <h2 style={{ 
              fontFamily: 'var(--font-display, "Playfair Display", serif)', 
              fontSize: '1.8rem', 
              color: '#0a1e3d', 
              marginBottom: 12 
            }}>
              No Reservations Yet
            </h2>
            <p style={{ color: '#666', marginBottom: 32, fontSize: '1rem' }}>
              {selectedFilter !== 'all' 
                ? `No ${selectedFilter} reservations found.` 
                : 'Start your luxury journey with us today!'}
            </p>
            <Link 
              to="/rooms" 
              style={{
                padding: '14px 32px',
                background: 'linear-gradient(135deg, #c9a84c, #b8923e)',
                borderRadius: '50px',
                color: 'white',
                textDecoration: 'none',
                fontWeight: 600,
                display: 'inline-block',
                transition: 'all 0.3s'
              }}
              onMouseEnter={e => {
                e.currentTarget.style.transform = 'translateY(-2px)';
                e.currentTarget.style.boxShadow = '0 10px 25px rgba(201,168,76,0.3)';
              }}
              onMouseLeave={e => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.boxShadow = 'none';
              }}
            >
              Browse Available Rooms
            </Link>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
            {filteredReservations.map((r, idx) => {
              const statusStyle = getStatusStyle(r.status);
              const checkInDate = new Date(r.check_in);
              const checkOutDate = new Date(r.check_out);
              const isExpanded = expandedId === r.id;

              return (
                <div
                  key={r.id}
                  style={{
                    background: 'white',
                    borderRadius: 20,
                    overflow: 'hidden',
                    boxShadow: '0 4px 6px rgba(0,0,0,0.05)',
                    transition: 'all 0.3s',
                    animation: `fadeInUp 0.5s ease ${idx * 0.05}s backwards`
                  }}
                  onMouseEnter={e => {
                    e.currentTarget.style.boxShadow = '0 10px 30px rgba(0,0,0,0.1)';
                    e.currentTarget.style.transform = 'translateY(-2px)';
                  }}
                  onMouseLeave={e => {
                    e.currentTarget.style.boxShadow = '0 4px 6px rgba(0,0,0,0.05)';
                    e.currentTarget.style.transform = 'translateY(0)';
                  }}
                >
                  {/* Main Card */}
                  <div style={{ padding: 24, cursor: 'pointer' }} onClick={() => setExpandedId(isExpanded ? null : r.id)}>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 20, alignItems: 'center' }}>
                      {/* Status Badge */}
                      <div style={{ minWidth: 100 }}>
                        <div style={{
                          display: 'inline-flex',
                          alignItems: 'center',
                          gap: 6,
                          padding: '6px 14px',
                          background: statusStyle.bg,
                          borderRadius: 100,
                          color: statusStyle.color,
                          fontSize: '0.75rem',
                          fontWeight: 600
                        }}>
                          <span>{statusStyle.icon}</span>
                          {getStatusLabel(r.status)}
                        </div>
                      </div>

                      {/* Booking Reference */}
                      <div style={{ flex: 1, minWidth: 150 }}>
                        <div style={{ fontSize: '0.7rem', color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: 4 }}>
                          Booking Reference
                        </div>
                        <div style={{ 
                          fontWeight: 700, 
                          color: '#0a1e3d', 
                          fontSize: '1rem',
                          fontFamily: 'monospace',
                          letterSpacing: '0.5px'
                        }}>
                          {r.booking_ref}
                        </div>
                      </div>

                      {/* Room Info */}
                      <div style={{ flex: 2, minWidth: 180 }}>
                        <div style={{ fontSize: '0.7rem', color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: 4 }}>
                          Room Details
                        </div>
                        <div style={{ fontWeight: 600, color: '#0a1e3d', marginBottom: 4 }}>
                          {r.room?.room_type?.name} • Room {r.room?.room_number}
                        </div>
                        <div style={{ fontSize: '0.8rem', color: '#666', display: 'flex', gap: 12, flexWrap: 'wrap' }}>
                          <span>👥 {r.guests} {r.guests === 1 ? 'Guest' : 'Guests'}</span>
                          <span>🛏️ {r.room?.room_type?.capacity} max</span>
                        </div>
                      </div>

                      {/* Dates */}
                      <div style={{ flex: 2, minWidth: 200 }}>
                        <div style={{ fontSize: '0.7rem', color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: 4 }}>
                          Stay Dates
                        </div>
                        <div style={{ fontWeight: 500, color: '#0a1e3d', marginBottom: 4 }}>
                          {checkInDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })} 
                          → {checkOutDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                        </div>
                        <div style={{ fontSize: '0.8rem', color: '#666' }}>
                          {r.nights} {r.nights === 1 ? 'night' : 'nights'}
                        </div>
                      </div>

                      {/* Price */}
                      <div style={{ minWidth: 120, textAlign: 'right' }}>
                        <div style={{ fontSize: '0.7rem', color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: 4 }}>
                          Total Amount
                        </div>
                        <div style={{ 
                          fontFamily: 'var(--font-display, "Playfair Display", serif)', 
                          fontSize: '1.4rem', 
                          color: '#c9a84c', 
                          fontWeight: 700 
                        }}>
                          ₱{Number(r.total_price).toLocaleString()}
                        </div>
                        <div style={{ fontSize: '0.7rem', color: '#666' }}>
                          {Math.round(Number(r.total_price) / r.nights).toLocaleString()}/night
                        </div>
                      </div>

                      {/* Expand Icon */}
                      <div style={{ color: '#c9a84c', fontSize: '1.2rem' }}>
                        {isExpanded ? '▲' : '▼'}
                      </div>
                    </div>
                  </div>

                  {/* Expanded Content */}
                  {isExpanded && (
                    <div style={{
                      borderTop: '1px solid #f0f0f0',
                      padding: '24px',
                      background: '#fafafa',
                      animation: 'slideDown 0.3s ease'
                    }}>
                      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: 24 }}>
                        {/* Additional Details */}
                        <div>
                          <h4 style={{ 
                            fontSize: '0.85rem', 
                            fontWeight: 600, 
                            color: '#0a1e3d', 
                            marginBottom: 12,
                            display: 'flex',
                            alignItems: 'center',
                            gap: 8
                          }}>
                            <span>📋</span> Booking Details
                          </h4>
                          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                            <div>
                              <span style={{ fontSize: '0.75rem', color: '#9ca3af' }}>Created:</span>
                              <div style={{ fontSize: '0.85rem', color: '#666' }}>
                                {new Date(r.created_at).toLocaleDateString('en-US', { 
                                  month: 'long', 
                                  day: 'numeric', 
                                  year: 'numeric',
                                  hour: '2-digit',
                                  minute: '2-digit'
                                })}
                              </div>
                            </div>
                            {r.special_requests && (
                              <div>
                                <span style={{ fontSize: '0.75rem', color: '#9ca3af' }}>Special Requests:</span>
                                <div style={{ fontSize: '0.85rem', color: '#666', marginTop: 4, fontStyle: 'italic' }}>
                                  "{r.special_requests}"
                                </div>
                              </div>
                            )}
                          </div>
                        </div>

                        {/* Room Amenities */}
                        {r.room?.room_type?.amenities && r.room.room_type.amenities.length > 0 && (
                          <div>
                            <h4 style={{ 
                              fontSize: '0.85rem', 
                              fontWeight: 600, 
                              color: '#0a1e3d', 
                              marginBottom: 12,
                              display: 'flex',
                              alignItems: 'center',
                              gap: 8
                            }}>
                              <span>✨</span> Room Amenities
                            </h4>
                            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                              {r.room.room_type.amenities.slice(0, 6).map(amenity => (
                                <span key={amenity} style={{
                                  padding: '4px 12px',
                                  background: 'white',
                                  borderRadius: 100,
                                  fontSize: '0.75rem',
                                  color: '#666',
                                  border: '1px solid #e5e7eb'
                                }}>
                                  {amenity}
                                </span>
                              ))}
                              {r.room.room_type.amenities.length > 6 && (
                                <span style={{
                                  padding: '4px 12px',
                                  background: '#f3f4f6',
                                  borderRadius: 100,
                                  fontSize: '0.75rem',
                                  color: '#666'
                                }}>
                                  +{r.room.room_type.amenities.length - 6} more
                                </span>
                              )}
                            </div>
                          </div>
                        )}

                        {/* Actions */}
                        <div>
                          <h4 style={{ 
                            fontSize: '0.85rem', 
                            fontWeight: 600, 
                            color: '#0a1e3d', 
                            marginBottom: 12,
                            display: 'flex',
                            alignItems: 'center',
                            gap: 8
                          }}>
                            <span>⚡</span> Actions
                          </h4>
                          <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
                            <Link 
                              to={`/rooms/${r.room?.id}`} 
                              style={{
                                padding: '10px 20px',
                                background: 'white',
                                border: '1px solid #c9a84c',
                                borderRadius: 8,
                                color: '#c9a84c',
                                textDecoration: 'none',
                                fontSize: '0.85rem',
                                fontWeight: 600,
                                transition: 'all 0.3s',
                                display: 'inline-flex',
                                alignItems: 'center',
                                gap: 6
                              }}
                              onMouseEnter={e => {
                                e.currentTarget.style.background = '#c9a84c';
                                e.currentTarget.style.color = 'white';
                              }}
                              onMouseLeave={e => {
                                e.currentTarget.style.background = 'white';
                                e.currentTarget.style.color = '#c9a84c';
                              }}
                            >
                              View Room Details →
                            </Link>

                            {r.can_cancel && (
                              <button
                                onClick={() => handleCancel(r.id)}
                                disabled={cancelling === r.id}
                                style={{
                                  padding: '10px 20px',
                                  background: '#ef4444',
                                  border: 'none',
                                  borderRadius: 8,
                                  color: 'white',
                                  fontSize: '0.85rem',
                                  fontWeight: 600,
                                  cursor: cancelling === r.id ? 'not-allowed' : 'pointer',
                                  transition: 'all 0.3s',
                                  opacity: cancelling === r.id ? 0.7 : 1,
                                  display: 'inline-flex',
                                  alignItems: 'center',
                                  gap: 6
                                }}
                                onMouseEnter={e => {
                                  if (cancelling !== r.id) {
                                    e.currentTarget.style.background = '#dc2626';
                                    e.currentTarget.style.transform = 'translateY(-1px)';
                                  }
                                }}
                                onMouseLeave={e => {
                                  if (cancelling !== r.id) {
                                    e.currentTarget.style.background = '#ef4444';
                                    e.currentTarget.style.transform = 'translateY(0)';
                                  }
                                }}
                              >
                                {cancelling === r.id ? 'Cancelling...' : 'Cancel Reservation ✗'}
                              </button>
                            )}

                            {r.status === 'confirmed' && (
                              <button
                                style={{
                                  padding: '10px 20px',
                                  background: '#10b981',
                                  border: 'none',
                                  borderRadius: 8,
                                  color: 'white',
                                  fontSize: '0.85rem',
                                  fontWeight: 600,
                                  cursor: 'pointer',
                                  transition: 'all 0.3s',
                                  display: 'inline-flex',
                                  alignItems: 'center',
                                  gap: 6
                                }}
                                onMouseEnter={e => {
                                  e.currentTarget.style.background = '#059669';
                                }}
                                onMouseLeave={e => {
                                  e.currentTarget.style.background = '#10b981';
                                }}
                              >
                                Download Invoice 📄
                              </button>
                            )}
                          </div>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Animations */}
      <style jsx>{`
        @keyframes fadeInUp {
          from {
            opacity: 0;
            transform: translateY(30px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        @keyframes slideDown {
          from {
            opacity: 0;
            transform: translateY(-10px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        @keyframes float {
          0%, 100% {
            transform: translate(0, 0);
          }
          50% {
            transform: translate(20px, -20px);
          }
        }

        @keyframes shimmer {
          0% {
            background-position: -1000px 0;
          }
          100% {
            background-position: 1000px 0;
          }
        }
      `}</style>
    </div>
  );
}
